module VideoCodec =
  struct
    type nonrec t =
      | AV1 
      | AVC_INTRA 
      | FRAME_CAPTURE 
      | H_264 
      | H_265 
      | MPEG2 
      | PRORES 
      | VC3 
      | VP8 
      | VP9 
      | XAVC 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | AV1 -> "AV1"
      | AVC_INTRA -> "AVC_INTRA"
      | FRAME_CAPTURE -> "FRAME_CAPTURE"
      | H_264 -> "H_264"
      | H_265 -> "H_265"
      | MPEG2 -> "MPEG2"
      | PRORES -> "PRORES"
      | VC3 -> "VC3"
      | VP8 -> "VP8"
      | VP9 -> "VP9"
      | XAVC -> "XAVC"
      | Non_static_id s -> s
    let of_string =
      function
      | "AV1" -> AV1
      | "AVC_INTRA" -> AVC_INTRA
      | "FRAME_CAPTURE" -> FRAME_CAPTURE
      | "H_264" -> H_264
      | "H_265" -> H_265
      | "MPEG2" -> MPEG2
      | "PRORES" -> PRORES
      | "VC3" -> VC3
      | "VP8" -> VP8
      | "VP9" -> VP9
      | "XAVC" -> XAVC
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string (string_of_xml ~kind:"enumeration VideoCodec" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"VideoCodec" j)
    let to_json = simple_to_json to_value
  end
