module ContainerType =
  struct
    type nonrec t =
      | F4V 
      | ISMV 
      | M2TS 
      | M3U8 
      | CMFC 
      | MOV 
      | MP4 
      | MPD 
      | MXF 
      | WEBM 
      | RAW 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | F4V -> "F4V"
      | ISMV -> "ISMV"
      | M2TS -> "M2TS"
      | M3U8 -> "M3U8"
      | CMFC -> "CMFC"
      | MOV -> "MOV"
      | MP4 -> "MP4"
      | MPD -> "MPD"
      | MXF -> "MXF"
      | WEBM -> "WEBM"
      | RAW -> "RAW"
      | Non_static_id s -> s
    let of_string =
      function
      | "F4V" -> F4V
      | "ISMV" -> ISMV
      | "M2TS" -> M2TS
      | "M3U8" -> M3U8
      | "CMFC" -> CMFC
      | "MOV" -> MOV
      | "MP4" -> MP4
      | "MPD" -> MPD
      | "MXF" -> MXF
      | "WEBM" -> WEBM
      | "RAW" -> RAW
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string (string_of_xml ~kind:"enumeration ContainerType" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"ContainerType" j)
    let to_json = simple_to_json to_value
  end
